onClick:
{{
appsmith.store.ultimaFCCreada

?

(
    storeValue(
        "idFCImpresion",
        appsmith.store.ultimaFCCreada
    )

    .then(() => ObtenerFCImpresion.run())

    .then((fc) => {

        storeValue(
            "fcImpresion",
            fc[0]
        );

        return ObtenerDetalleFCImpresion.run();

    })

    .then((detalle) => {

        return storeValue(
            "detalleFCImpresion",
            detalle
        );

    })

    .then(() => {

        download(
            JS_ImpresionFC.generarHTMLFC(),
            "FC-" +
            String(
                appsmith.store.ultimaFCCreada
            ).padStart(6,"0")
            +
            ".html",
            "text/html"
        );

        showAlert(
            "Factura cargada e impresa correctamente",
            "success"
        );

    })

)

:

showAlert(
    "No existe una factura creada en esta sesión",
    "warning"
)
}}

tooltip:
{{
!appsmith.store.ultimaFCCreada
    ? "No existe una factura trabajada en esta sesión"
    : ""
}}
